module freq_div (
    input CLK_in,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1,
    input RST
);

    reg [3:0] cnt_10;
    reg [6:0] cnt_100;

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            CLK_50 <= 1'b0;
            cnt_10 <= 4'd0;
            cnt_100 <= 7'd0;
        end else begin
            CLK_50 <= ~CLK_50;

            if (cnt_10 == 4'd9) begin
                cnt_10 <= 4'd0;
                CLK_10 <= ~CLK_10;
            end else begin
                cnt_10 <= cnt_10 + 1;
            end

            if (cnt_100 == 7'd99) begin
                cnt_100 <= 7'd0;
                CLK_1 <= ~CLK_1;
            end else begin
                cnt_100 <= cnt_100 + 1;
            end
        end
    end

endmodule
